from xml.etree import ElementTree as ET

def validate_xml(file):
    try:
        with open(file, 'r') as f:
            ET.parse(f)  # This will throw an exception if the file is not a valid XML document
        
        print("The uploaded file is a valid XML.")
    
    except ET.ParseError:
        print('The uploaded file is NOT a valid XML.')